div.script:
function toggleInviteFields() {
var t = document.getElementById('invite_type').value;
document.getElementById('once_fields_wrap').style.display = t === 'once' ? 'block' : 'none';
document.getElementById('freq_fields_wrap').style.display = t === 'frequent' ? 'block' : 'none';
}

function toggleCabFields() {
var m = document.getElementById('cab_mode').value;
document.getElementById('cab_once_wrap').style.display = m === 'once' ? 'block' : 'none';
document.getElementById('cab_freq_wrap').style.display = m === 'frequent' ? 'block' : 'none';
}

function toggleDeliveryFields() {
var m = document.getElementById('delivery_mode').value;
document.getElementById('delivery_once_wrap').style.display = m === 'once' ? 'block' : 'none';
document.getElementById('delivery_freq_wrap').style.display = m === 'frequent' ? 'block' : 'none';
}

function toggleVHFields() {
var t = document.getElementById('vh_entry_type').value;
document.getElementById('vh_once_wrap').style.display = t === 'once' ? 'block' : 'none';
document.getElementById('vh_freq_wrap').style.display = t === 'frequent' ? 'block' : 'none';
}

function checkAmenityType(el) {
var label = el.closest('label');
document.querySelectorAll('.amenity-option').forEach(function(l) {
l.style.borderColor = '#e5e7eb';
l.style.background = '#fff';
});
label.style.borderColor = '#1a73e8';
label.style.background = '#eff6ff';
var isPaid = label.querySelector('.amenity-option span') ? false : false;
// Show paid note based on selection - handled server side
}
document.querySelectorAll('.amenity-option input').forEach(function(r) {
r.addEventListener('change', function() { checkAmenityType(this); });
});
